UPDATE public.projects SET last_edited_by = 'jbeehner@umich.edu', updated_at = now(), study_species = ARRAY['Cebus capucinus']::text[], metadata = COALESCE(metadata,'{}'::jsonb) || '{"planning_priorities": ["Define the behavior to measure", "Define the behavioral tasks the subject should perform", "Which data modalities and recording devices to use"], "planning_priorities_other": "Sample size, statistical modeling for the data, logistics for field personnel", "data_types_collected": ["Behavioral data (video, motion capture, eye tracking, gait)", "Cognitive performance data", "Environmental data", "Biochemical data (hormone levels)", "Social interaction data"], "data_types_other": "Life history data on our subjects (early life adversity, chronic stress, acute stress)", "neural_recording_details": "Since we are unable to get at any of the above in our wild subjects, we are using sign-tracking and goal-tracking behavior as a window into the brains organization and decision-making processes.", "behavioral_recording_tech": ["Video Recording", "Motion Capture Systems", "GPS Tracking", "Acoustic Recording", "Behavioral Coding Software", "Touchscreen-based Cognitive Testing Systems (for animals)", "Smart Devices and Mobile Apps"], "behavioral_brands": "GoPro Hero10 with motion sensor software firmware, trained human observers on the ground, Garmin GPS units, DeepLabCut, Wildlife Acoustics passive acoustic recorders, MedAssociates sign- and goal-tracking system, LaFayette software for the sign- and goal-tracking system", "hand_coding_method": "Yes, for most of our behavior, we use iPads scored manually from observers on the ground", "behaviors_of_interest": ["Locomotion and Movement", "Cognitive and Memory Tasks", "Social Interactions", "Feeding and Drinking", "Exploratory Behavior", "Emotional and Stress Responses", "Reproductive Behaviors"], "behaviors_details": "We are interested in evolutionary fitness broadly speaking - so anything that picks up on performance, survival, or reproductive success is key", "behavioral_data_formats": ["CSV"], "behavioral_formats_other": "All of our behavioral data are in .csv files stored in a relational database that is query-able using R code", "data_management_systems": ["Shared data storage", "Custom database", "Git / GitHub"], "data_management_other": "All of our behavioral data are in .csv files stored in a relational database that is query-able using R code", "primary_storage": "Cloud storage", "primary_storage_details": "We store all our data on U Michigan servers (quick access data are on Google Drive, large format files are on MBox, a form of DropBox, and really large video files are stored on a Turbo Drive.", "data_sync_methods": ["Timestamping", "GPS Time", "Event Markers"], "behavioral_feature_detection": ["Manual feature annotation", "Statistical methods", "Computer vision (pose estimation)", "Domain-specific open source (BORIS, DeepLabCut)"], "analysis_languages": ["Python", "R"], "use_analysis_method": ["Computational models (Markov chains)", "Supervised ML", "Deep learning", "Reinforcement learning"], "use_analysis_types": ["Statistical analysis", "Dimensionality reduction", "Bayesian inference", "Network analysis", "Correlation analysis", "Regression models"], "analysis_software": ["R packages (caret)"], "analysis_platforms": ["Cloud-based platforms (Colab, AWS)", "HPC systems"], "reliability_methods": ["Peer review code within lab", "Replication", "Documented pipelines"], "other_sharing_methods": ["Google Drive", "Dropbox", "OneDrive", "Institutional repositories"], "all_data_public_immediately": true, "reuse_data_origins": ["Project internal team data"], "reuse_purposes": ["Replication", "Validation and verification", "Meta-analyses", "Longitudinal studies", "Methodological development", "Secondary analysis", "Cross-disciplinary research", "Educational purposes"], "help_needed": "I think the thing we need the most help with is the integration of all sources of data into a pipeline. We have our usual pipelines but adding in the AI data from videos beyond DeepLabCut is something we are currently working on.", "resources_to_share": "We are the first to implement vocal tracking of animals across a natural forest. We would like to share our lessons learned (once we learn them!)", "additional_info": "Long-term study on wild Capuchin monkeys at Taboga field site. Data Management Plan covers: routine demographic/behavioral observations (Animal Observer iPad software, .csv); vocal recordings (.wav from Marantz/Wildlife Acoustics Song Meter Mini); video (.mov from iPads/iPhones/GoPro/drones); GPS tracks; identification photos (Nikon D40, trail cams, drones); abiotic measurements (temperature, rainfall); MedAssociates Pavlovian conditioning output (.xls); DeepLabCut output (.xls). Sharing: data deposited to BBQS Archive every 6 months; published data available on publication; unpublished within 1 year of award end. PI directors: Drs. Beehner, Bergman (U Michigan), Benitez (Emory). Field team: 5 full-time Costa Rican research assistants. Data verification: same-day field manager check, automated DB checks on entry, analyst checks. Code: MATLAB scripts and pre-trained DeepLabCut networks released open-source on GitHub; vocal AI algorithm to be released open-source; tablet app for visual+vocal animal ID under development with U Michigan LSA Tech Services.", "neural_data_size_per_year": "Actual neural data - none", "behavioral_data_size_per_year": "with the added video, we are expecting probably between 100GB and 1TB", "single_unit_upload_size": "2 GB / session (estimate)"}'::jsonb WHERE grant_number = 'R34DA061925';